var e=[{id:`L2_1`,type:`dialog`,speaker:`MORDRED_ROOT_NULL_NULL`,text:{KOREA:`전 사람들을 지키고 싶어요. 세상은 스스로의 힘만 가지고 해쳐나가기엔 너무 혹독하잖아요?`,JPN:`私は人々を守りたいのです。この世は自らの力だけで乗り越えていくにはあまりにも苛酷じゃないですか？`,ENG:`I want to protect people. But the world is too harsh for someone to live on their own, right?`,TWN:`我想保護大家。光憑一己之力要在這個世界生存下去，豈不是太嚴苛？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORDRED_ROOT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MORDRED_ROOT_NULL_NULL`,text:{KOREA:`제 힘으로 지키는 건 당신의 안전이지만, 부디 제 존재가 당신 마음도 지켜주길 바라요. 저에겐 이미 당신이 그런 존재니까요.`,JPN:`私の力で守るのはあなたの安全ですが、どうか私の存在があなたの心も守ってくれることを願っています。 私にはすでにあなたがそのような存在ですから。`,ENG:`I'll be using my strength to provide you with safety, but I hope that my existence will also protect your mind. Because you're already someone like that for me.`,TWN:`我現在是用我的力量在守護你的安全，但我更希望我的存在也能夠守護你的心。因為對我來說，你就是這樣的存在。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORDRED_ROOT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};